/**
 * Email notification handler for order status changes.
 *
 * Subscribes to order events via EventBus and formats email notifications.
 * Follows the same EventBus subscription pattern as NotificationService.
 *
 * Depends on:
 * - EventBus (event system) for receiving order lifecycle events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  from: string;
  subject: string;
  htmlBody: string;
  textBody: string;
  sentAt: Date;
}

const STATUS_LABELS: Record<OrderStatus, string> = {
  pending: 'Order Received',
  confirmed: 'Order Confirmed',
  shipped: 'Order Shipped',
  delivered: 'Order Delivered',
  cancelled: 'Order Cancelled',
};

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];
  private senderAddress: string;

  constructor(
    private eventBus: EventBus,
    senderAddress = 'orders@taskflowpro.com',
  ) {
    this.senderAddress = senderAddress;
    this.registerHandlers();
  }

  /**
   * Register EventBus handlers for order events that trigger emails.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Send order confirmation email when a new order is created.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation email for order ${event.order.id}`);

    const itemRows = event.order.items
      .map(
        (item) =>
          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`,
      )
      .join('\n');

    const itemList = event.order.items
      .map((item) => `- ${item.name} x${item.quantity} @ $${item.unitPrice.toFixed(2)}`)
      .join('\n');

    const htmlBody = `<h1>Order Confirmation</h1>
<p>Thank you for your order, ${event.user.name}!</p>
<p>Order ID: <strong>${event.order.id}</strong></p>
<table>
<tr><th>Item</th><th>Qty</th><th>Price</th></tr>
${itemRows}
</table>
<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`;

    const textBody = `Order Confirmation

Thank you for your order, ${event.user.name}!

Order ID: ${event.order.id}

Items:
${itemList}

Total: $${event.order.total.toFixed(2)}`;

    this.sendEmail({
      to: event.user.email,
      subject: `Order Confirmation - ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Send status update email when an order's status changes.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    const newLabel = STATUS_LABELS[event.newStatus as OrderStatus] ?? event.newStatus;
    const prevLabel = STATUS_LABELS[event.previousStatus as OrderStatus] ?? event.previousStatus;

    this.logger.info(
      `Sending status email for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const htmlBody = `<h1>${newLabel}</h1>
<p>Your order <strong>${event.order.id}</strong> has been updated.</p>
<p>Status changed from <em>${prevLabel}</em> to <em>${newLabel}</em>.</p>
${event.newStatus === 'shipped' ? '<p>Your order is on its way!</p>' : ''}
${event.newStatus === 'delivered' ? '<p>Your order has been delivered. Enjoy!</p>' : ''}
${event.newStatus === 'cancelled' ? '<p>Your order has been cancelled. If this was unexpected, please contact support.</p>' : ''}`;

    const textBody = `${newLabel}

Your order ${event.order.id} has been updated.
Status changed from ${prevLabel} to ${newLabel}.${
      event.newStatus === 'shipped' ? '\nYour order is on its way!' : ''
    }${event.newStatus === 'delivered' ? '\nYour order has been delivered. Enjoy!' : ''}${
      event.newStatus === 'cancelled'
        ? '\nYour order has been cancelled. If this was unexpected, please contact support.'
        : ''
    }`;

    this.sendEmail({
      to: event.order.userId,
      subject: `${newLabel} - ${event.order.id}`,
      htmlBody,
      textBody,
    });
  }

  /**
   * Send an email (in-memory for this demo).
   */
  private sendEmail(params: {
    to: string;
    subject: string;
    htmlBody: string;
    textBody: string;
  }): void {
    const email: EmailMessage = {
      to: params.to,
      from: this.senderAddress,
      subject: params.subject,
      htmlBody: params.htmlBody,
      textBody: params.textBody,
      sentAt: new Date(),
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${params.to}: ${params.subject}`);
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get emails sent to a specific address.
   */
  getEmailsTo(address: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.to === address);
  }

  /**
   * Get the count of sent emails.
   */
  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailNotificationHandler } from '../../src/notifications/email-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('EmailNotificationHandler', () => {
  let eventBus: EventBus;
  let emailHandler: EmailNotificationHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    emailHandler = new EmailNotificationHandler(eventBus);
  });

  describe('order:created email', () => {
    const makeCreatedEvent = (overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent => ({
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
        ],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
      ...overrides,
    });

    it('should send confirmation email on order created', async () => {
      await eventBus.emit(makeCreatedEvent());

      const emails = emailHandler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('alice@example.com');
      expect(emails[0]?.from).toBe('orders@taskflowpro.com');
      expect(emails[0]?.subject).toContain('Order Confirmation');
      expect(emails[0]?.subject).toContain('order-1');
    });

    it('should include items in HTML body', async () => {
      await eventBus.emit(makeCreatedEvent());

      const email = emailHandler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('$20.00');
      expect(email.htmlBody).toContain('Alice');
    });

    it('should include items in text body', async () => {
      await eventBus.emit(makeCreatedEvent());

      const email = emailHandler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('$20.00');
      expect(email.textBody).toContain('Alice');
    });

    it('should include multiple items', async () => {
      const event = makeCreatedEvent({
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
      });

      await eventBus.emit(event);

      const email = emailHandler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Widget');
      expect(email.htmlBody).toContain('Gadget');
      expect(email.textBody).toContain('Widget x2');
      expect(email.textBody).toContain('Gadget x1');
    });
  });

  describe('order:status-changed email', () => {
    const makeStatusEvent = (
      previousStatus: string,
      newStatus: string,
    ): OrderStatusChangedEvent => ({
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 20,
        status: newStatus as 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus,
      newStatus,
      timestamp: new Date(),
    });

    it('should send email on status change', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      const emails = emailHandler.getSentEmails();
      expect(emails).toHaveLength(1);
      expect(emails[0]?.to).toBe('user-1');
      expect(emails[0]?.from).toBe('orders@taskflowpro.com');
      expect(emails[0]?.subject).toContain('Order Confirmed');
    });

    it('should use human-readable labels in subject', async () => {
      await eventBus.emit(makeStatusEvent('confirmed', 'shipped'));

      const email = emailHandler.getSentEmails()[0]!;
      expect(email.subject).toBe('Order Shipped - order-1');
    });

    it('should include status change details in HTML body', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      const email = emailHandler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('Order Confirmed');
      expect(email.htmlBody).toContain('order-1');
      expect(email.htmlBody).toContain('Order Received');
    });

    it('should include status change details in text body', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));

      const email = emailHandler.getSentEmails()[0]!;
      expect(email.textBody).toContain('Order Confirmed');
      expect(email.textBody).toContain('Order Received');
    });

    it('should add shipping message for shipped status', async () => {
      await eventBus.emit(makeStatusEvent('confirmed', 'shipped'));

      const email = emailHandler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('on its way');
      expect(email.textBody).toContain('on its way');
    });

    it('should add delivery message for delivered status', async () => {
      await eventBus.emit(makeStatusEvent('shipped', 'delivered'));

      const email = emailHandler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('has been delivered');
      expect(email.textBody).toContain('has been delivered');
    });

    it('should add cancellation message for cancelled status', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'cancelled'));

      const email = emailHandler.getSentEmails()[0]!;
      expect(email.htmlBody).toContain('has been cancelled');
      expect(email.textBody).toContain('contact support');
    });

    it('should handle all status transitions', async () => {
      await eventBus.emit(makeStatusEvent('pending', 'confirmed'));
      await eventBus.emit(makeStatusEvent('confirmed', 'shipped'));
      await eventBus.emit(makeStatusEvent('shipped', 'delivered'));

      expect(emailHandler.getSentEmailCount()).toBe(3);

      const subjects = emailHandler.getSentEmails().map((e) => e.subject);
      expect(subjects[0]).toContain('Order Confirmed');
      expect(subjects[1]).toContain('Order Shipped');
      expect(subjects[2]).toContain('Order Delivered');
    });
  });

  describe('email management', () => {
    it('should count sent emails', async () => {
      expect(emailHandler.getSentEmailCount()).toBe(0);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(emailHandler.getSentEmailCount()).toBe(1);
    });

    it('should filter emails by recipient', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(emailHandler.getEmailsTo('user-1')).toHaveLength(1);
      expect(emailHandler.getEmailsTo('user-2')).toHaveLength(0);
    });

    it('should clear emails', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      emailHandler.clearEmails();
      expect(emailHandler.getSentEmailCount()).toBe(0);
    });

    it('should allow custom sender address', () => {
      const customHandler = new EmailNotificationHandler(eventBus, 'custom@example.com');
      // Trigger an event to check the from field
      eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const emails = customHandler.getEmailsTo('user-1');
      expect(emails[0]?.from).toBe('custom@example.com');
    });
  });

  describe('integration with EventBus', () => {
    it('should work alongside NotificationService on same EventBus', async () => {
      // Both handlers subscribe to same events — EventBus supports multiple listeners
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      resetNotificationIdCounter();
      const notifService = new NotificationService(eventBus);

      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      // Both handlers should have processed the event
      expect(emailHandler.getSentEmailCount()).toBe(1);
      expect(notifService.getNotificationCount()).toBe(1);
    });

    it('should log events in EventBus event log', async () => {
      await eventBus.emit({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'shipped',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      });

      const log = eventBus.getEventLog();
      expect(log).toHaveLength(1);
      expect(log[0]?.type).toBe('order:status-changed');
    });
  });
});

